<?php

namespace Tests\Feature;

use Tests\TestCase;
use App\Services\S3StorageService;
use Illuminate\Support\Facades\Storage;
use Exception;

class S3StorageServiceTest extends TestCase
{
    protected S3StorageService $s3Service;
    protected string $image;
    protected string $document;

    protected function setUp(): void
    {
        parent::setUp();
        
        // Mocking S3 Disk
        Storage::fake('s3');
        
        $this->s3Service = new S3StorageService();
        $this->image = 'data:image/jpeg;base64,';

        $this->document = 'data:application/pdf;base64,';
    }

    /** @test */
    public function test_it_can_upload_base64_image_with_compression()
    {
        // Mocking Gambar PNG 1x1 pixel (Base64)
        $base64Image = $this->image;

        // Eksekusi
        $path = $this->s3Service->uploadBase64($base64Image, 'uploads/test', 'foto');

        // Assertions
        $this->assertNotNull($path);
        $this->assertStringContainsString('uploads/test', $path);
        
        // Cek apakah file ada di disk fake
        Storage::disk('s3')->assertExists($path);
        
        // Karena service kita mengonversi semua foto ke JPEG (toJpeg(80)), cek ekstensinya
        $this->assertStringEndsWith('.jpg', $path);
    }

    /** @test */
    public function test_it_fails_if_base64_format_is_invalid()
    {
        $invalidBase64 = "bukan-format-base64-yang-benar";

        $this->expectException(Exception::class);
        $this->expectExceptionMessage("Format Base64 tidak valid");

        $this->s3Service->uploadBase64($invalidBase64, 'test', 'foto');
    }

    /** @test */
    public function test_it_can_generate_temporary_url()
    {
        $base64 = $this->image;
        $path = $this->s3Service->uploadBase64($base64, 'secure', 'foto');

        $url = $this->s3Service->getDynamicUrl($path, 10);

        $this->assertNotNull($url);
        // Temporary URL biasanya mengandung query params (signature)
        $this->assertStringContainsString('?', $url);
    }

    /** @test */
    public function test_it_can_delete_file()
    {
        $base64 = $this->image;
        $path = $this->s3Service->uploadBase64($base64, 'delete-me', 'foto');

        $deleted = $this->s3Service->delete($path);

        $this->assertTrue($deleted);
        Storage::disk('s3')->assertMissing($path);
    }

    /** @test */
    public function test_it_fails_if_mime_type_not_supported_for_foto()
    {
        // Mocking Base64 yang isinya teks/dokumen tapi dikirim sebagai kategori 'foto'
        $base64Pdf = $this->document;

        $this->expectException(Exception::class);
        // Pesan error disesuaikan dengan yang ada di service
        $this->expectExceptionMessage("Format file (application/pdf) tidak diizinkan");

        $this->s3Service->uploadBase64($base64Pdf, 'test', 'foto');
    }

    /** @test */
    public function test_it_can_upload_document_without_compression()
    {
        // Mocking Base64 PDF (dummy content)
        $base64Pdf = $this->document;

        $path = $this->s3Service->uploadBase64($base64Pdf, 'documents', 'dokumen');

        $this->assertNotNull($path);
        $this->assertStringEndsWith('.pdf', $path);
        Storage::disk('s3')->assertExists($path);
    }

    /** @test */
    public function test_it_returns_null_for_non_existent_file_url()
    {
        // Mencoba mengambil URL dari path yang tidak pernah ada
        $url = $this->s3Service->getDynamicUrl('path/tidak/ada.jpg');

        $this->assertNull($url);
    }

    /** @test */
    public function test_it_returns_false_when_deleting_non_existent_file()
    {
        // Mencoba menghapus file yang tidak ada
        $deleted = $this->s3Service->delete('path/salah.jpg');

        $this->assertFalse($deleted);
    }

    /** @test */
    public function test_it_handles_unknown_category()
    {
        $this->expectException(Exception::class);
        $this->expectExceptionMessage("Kategori validasi [musik] tidak ditemukan");

        // 'musik' tidak ada dalam array $rules di service
        $this->s3Service->uploadBase64($this->image, 'test', 'musik');
    }
}